// Payload: evolution_instance (Edge send-whatsapp-confirmation), confirmação OU cancelamento (type: 'cancel')
// Base da Evolution SEM $env (n8n pode bloquear $env no Code)
const EVOLUTION_BASE_DEFAULT = 'http://72.60.159.183:8080';
const item = $input.first().json;
const body = item.body && typeof item.body === 'object' ? item.body : item;
const phone = String(body.client_phone || body.phone || '').replace(/\D/g, '');
const number = phone.startsWith('55') ? phone : (phone ? '55' + phone : '');

const clientName = body.client_name || body.clientName || 'Cliente';
const barberName = body.barber_name || body.barberName || 'Barbeiro';
const serviceName = body.service_name || body.serviceName || 'Serviço';
const date = body.appointment_date || body.date || '';
const time = body.appointment_time || body.time || '';
const price = body.service_price != null ? body.service_price : body.price;
const isCancel = body.type === 'cancel';

const inst = String(body.evolution_instance || 'caio_zap').trim().replace(/[^a-zA-Z0-9_-]/g, '') || 'caio_zap';
let base = String(EVOLUTION_BASE_DEFAULT);
if (base.endsWith('/')) base = base.slice(0, -1);
const sendUrl = base + '/message/sendText/' + inst;

let dateFormatted = (date && typeof date === 'string') ? String(date).trim() : '';
if (dateFormatted.length >= 10 && dateFormatted.includes('-')) {
  const parts = dateFormatted.slice(0, 10).split('-');
  if (parts.length === 3 && parts[0] && parts[1] && parts[2]) {
    dateFormatted = `${parts[2]}/${parts[1]}/${parts[0]}`;
  }
}
const timeFormatted = (time || '').toString().slice(0, 5);
const priceStr = price != null ? `R$ ${Number(price).toFixed(2).replace('.', ',')}` : '';

const message = isCancel
  ? `❌ *Agendamento cancelado*\n\nOlá, ${clientName}!\n\nSeu agendamento foi cancelado.\n📅 Data: ${dateFormatted}\n🕐 Horário: ${timeFormatted}\n✂️ Serviço: ${serviceName}\n👤 Barbeiro: ${barberName}\n\nSe precisar, agende um novo horário pelo app.`
  : `✅ *Agendamento confirmado!*\n\nOlá, ${clientName}!\n\nSeu horário foi reservado:\n📅 Data: ${dateFormatted}\n🕐 Horário: ${timeFormatted}\n✂️ Serviço: ${serviceName}\n👤 Barbeiro: ${barberName}${priceStr ? '\n💰 Valor: ' + priceStr : ''}\n\nAté lá!`;

return [{ json: { number, message, sendUrl, evolution_instance: inst, raw: body } }];
